// ---------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------
func buildNodesQueryString(filter models.NodeFilter) string {
	params := []string{}
	if filter.Name.Set && filter.Name.Value != "" {
		params = append(params, "name="+filter.Name.Value)
	}
	if filter.SortBy.Set {
		params = append(params, "sort="+filter.SortBy.Value)
	}
	if filter.SortOrder.Set {
		params = append(params, "order="+filter.SortOrder.Value)
	}
	return strings.Join(params, "&")
}

func buildNodesPageURL(baseQuery string, page int) string {
	if baseQuery == "" {
		return fmt.Sprintf("/nodes?page=%d", page)
	}
	return fmt.Sprintf("/nodes?%s&page=%d", baseQuery, page)
}

